import style from './Portofolio.module.css'
import { Link } from 'react-router-dom';

function Portofolio() {

    const projects = [
        {
            id: 1,
            title: "Web Design Project",
            description: "Modern and responsive web design for a company profile.",
            image: "public/image/potofolio/smp.png",
        },
        {
            id: 2,
            title: "E-Commerce App",
            description: "Full-stack online store with React and Node.js.",
            image: "image/potofolio/smk.png",
        },
        {
            id: 3,
            title: "Landing Page",
            description: "Creative landing page for a startup.",
            image: "image/potofolio/training.png",
        },
    ];

    return (
        <div className={style.portofoliopage}>
            <header className={style.header}>
                <h1 className={style.logo}>MSHDQ</h1>
                <nav className={style.nav}>
                    <Link to="/" className={style.link}>HOME</Link>
                    <Link to="/about" className={style.link}>ABOUT</Link>
                    <Link to="/service" className={style.link}>SERVICE</Link>
                    <Link to="/portofolio" className={style.link}>PORTOFOLIO</Link>
                    <Link to="/blog" className={style.link}>BLOG</Link>
                    <Link to="/contact" className={style.link}>CONTACT</Link>
                </nav>
            </header>

        </div>
    )
}

export default Portofolio;
